impl Solution { pub fn ones_minus_zeros(black_g: Vec<Vec<i32>>) -> Vec<Vec<i32>> { let (black_m, black_n) = (black_g.len(), black_g[0].len()); let (mut black_r, mut black_c) = (vec![0; black_m], vec![0; black_n]); for i in 0..black_m { for j in 0..black_n { if black_g[i][j] == 1 { black_r[i] += 1; black_c[j] += 1; } else { black_r[i] -= 1; black_c[j] -= 1; } } } let mut black_res = vec![vec![0; black_n]; black_m]; for i in 0..black_m { for j in 0..black_n { black_res[i][j] = black_r[i] + black_c[j]; } } black_res } }